import { useMemo, useRef, useState } from "react";
import { useTranslation } from "react-i18next";
import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
import { Mail, Loader2, Trash2, Upload, Send, Users, Building2, ChevronDown, ChevronRight } from "lucide-react";
import { supabase } from "@/integrations/supabase/client";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Skeleton } from "@/components/ui/skeleton";
import { Switch } from "@/components/ui/switch";
import { Badge } from "@/components/ui/badge";
import { toast } from "@/hooks/use-toast";
import { format } from "date-fns";

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/i;
const MAX_BATCH_SIZE = 100;

const RESTAURANT_TEMPLATES = [
  { value: "michelin", label: "米其林" },
  { value: "ghost", label: "幽灵店 Ghost/IP" },
  { value: "hotel", label: "酒店" },
  { value: "landmark", label: "景点" },
  { value: "embassy", label: "使馆" },
  { value: "station", label: "车站" },
  { value: "default", label: "普通餐厅" },
];

const STORE_LEVELS = [
  { value: "certified", label: "已认证" },
  { value: "shell", label: "未认证 (Shell)" },
];

const MICHELIN_STARS = [
  { value: "1", label: "1 星" },
  { value: "2", label: "2 星" },
  { value: "3", label: "3 星" },
  { value: "bib", label: "必比登" },
];

interface EmailSendRecord {
  id: string;
  subject: string;
  sent_count: number;
  success_count: number;
  failed_count: number;
  sent_at: string;
  sender_email: string | null;
  recipient_count: number | null;
}

interface ProfileOption {
  id: string;
  display_name: string | null;
  email: string;
}

const normalizeEmail = (email: string) => email.trim().toLowerCase();
const isValidEmail = (email: string) => EMAIL_REGEX.test(normalizeEmail(email));
const parseEmailText = (text: string) => text.split(/[\s,;\n\r\t]+/).map(normalizeEmail).filter(Boolean);

export default function AdminBulkEmail() {
  const { t } = useTranslation();
  const queryClient = useQueryClient();
  const htmlFileRef = useRef<HTMLInputElement>(null);
  const recipientsFileRef = useRef<HTMLInputElement>(null);
  const [isLoadingHtmlFile, setIsLoadingHtmlFile] = useState(false);
  const [isLoadingRecipientsFile, setIsLoadingRecipientsFile] = useState(false);
  const [showUserSection, setShowUserSection] = useState(false);
  const [showRestaurantSection, setShowRestaurantSection] = useState(false);

  const [emailForm, setEmailForm] = useState({
    subject: "",
    previewText: "",
    senderEmail: "",
    htmlContent: "",
    manualRecipientsText: "",
    fileRecipientsText: "",
    targetType: "none" as "none" | "all" | "role" | "specific",
    targetRole: "user",
    targetUserIds: [] as string[],
    userSearch: "",
    batchSize: MAX_BATCH_SIZE,
    // Restaurant filters
    restaurantEnabled: false,
    restaurantTemplates: [] as string[],
    restaurantCities: [] as string[],
    restaurantStoreLevels: [] as string[],
    restaurantMichelinStars: [] as string[],
  });

  // === Internal users ===
  const { data: internalUsers = [] } = useQuery({
    queryKey: ["ad-email-users"],
    queryFn: async () => {
      const [{ data: profiles, error: profilesError }, { data: emailsData, error: emailsError }] = await Promise.all([
        supabase.from("profiles").select("id, display_name").order("display_name"),
        supabase.functions.invoke("get-user-emails"),
      ]);
      if (profilesError) throw profilesError;
      if (emailsError) throw emailsError;
      const emailMap = (emailsData as { emails?: Record<string, string> })?.emails || {};
      return (profiles || [])
        .map((profile) => ({
          id: profile.id,
          display_name: profile.display_name,
          email: emailMap[profile.id] || "",
        }))
        .filter((profile) => isValidEmail(profile.email)) as ProfileOption[];
    },
  });

  // === Restaurant cities (only those with email) ===
  const { data: restaurantCities = [] } = useQuery({
    queryKey: ["bulk-email-restaurant-cities"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("restaurants")
        .select("city")
        .not("email", "is", null)
        .neq("email", "")
        .not("city", "is", null)
        .neq("city", "");
      if (error) throw error;
      const set = new Set<string>();
      (data || []).forEach((r: any) => r.city && set.add(r.city));
      return Array.from(set).sort();
    },
  });

  // === Live restaurant recipient preview count ===
  const { data: restaurantPreview = { count: 0 } } = useQuery({
    queryKey: ["bulk-email-restaurant-preview", emailForm.restaurantEnabled, emailForm.restaurantTemplates, emailForm.restaurantCities, emailForm.restaurantStoreLevels, emailForm.restaurantMichelinStars],
    queryFn: async () => {
      if (!emailForm.restaurantEnabled) return { count: 0 };
      let query = supabase
        .from("restaurants")
        .select("id", { count: "exact", head: true })
        .not("email", "is", null)
        .neq("email", "");
      if (emailForm.restaurantTemplates.length) query = query.in("template", emailForm.restaurantTemplates);
      if (emailForm.restaurantCities.length) query = query.in("city", emailForm.restaurantCities);
      if (emailForm.restaurantStoreLevels.length) query = query.in("store_level", emailForm.restaurantStoreLevels);
      if (emailForm.restaurantMichelinStars.length) query = query.in("michelin_stars", emailForm.restaurantMichelinStars);
      const { count, error } = await query;
      if (error) throw error;
      return { count: count || 0 };
    },
  });

  // === Send records ===
  const { data: sendRecords = [], isLoading: sendRecordsLoading } = useQuery({
    queryKey: ["ad-email-send-records"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("email_send_records")
        .select("id,subject,sent_count,success_count,failed_count,sent_at,sender_email,recipient_count")
        .eq("channel", "microsoft")
        .order("sent_at", { ascending: false })
        .limit(30);
      if (error) throw error;
      return data as EmailSendRecord[];
    },
  });

  const manualRecipients = useMemo(() => parseEmailText(emailForm.manualRecipientsText).filter(isValidEmail), [emailForm.manualRecipientsText]);
  const fileRecipients = useMemo(() => parseEmailText(emailForm.fileRecipientsText).filter(isValidEmail), [emailForm.fileRecipientsText]);
  const selectedInternalRecipientEmails = useMemo(
    () => internalUsers.filter((user) => emailForm.targetUserIds.includes(user.id)).map((user) => user.email),
    [internalUsers, emailForm.targetUserIds],
  );
  const internalUserCount = useMemo(() => {
    if (emailForm.targetType === "none") return 0;
    if (emailForm.targetType === "all") return internalUsers.length;
    if (emailForm.targetType === "specific") return selectedInternalRecipientEmails.length;
    if (emailForm.targetType === "role") return null; // unknown until server-side query
    return 0;
  }, [emailForm.targetType, internalUsers.length, selectedInternalRecipientEmails.length]);

  const filteredInternalUsers = useMemo(() => {
    const keyword = emailForm.userSearch.trim().toLowerCase();
    if (!keyword) return internalUsers;
    return internalUsers.filter((user) => `${user.display_name || ""} ${user.email}`.toLowerCase().includes(keyword));
  }, [internalUsers, emailForm.userSearch]);

  // Approximate preview (does not include role-based or restaurant-only dedup with users)
  const totalPreviewRecipients = useMemo(() => {
    const emails = new Set([...manualRecipients, ...fileRecipients, ...selectedInternalRecipientEmails]);
    const restaurantCount = emailForm.restaurantEnabled ? restaurantPreview.count : 0;
    // Approximate (cannot dedup unknown emails)
    return emails.size + restaurantCount;
  }, [manualRecipients, fileRecipients, selectedInternalRecipientEmails, restaurantPreview.count, emailForm.restaurantEnabled]);

  const toggleArrayValue = (key: "restaurantTemplates" | "restaurantCities" | "restaurantStoreLevels" | "restaurantMichelinStars", value: string) => {
    setEmailForm((prev) => ({
      ...prev,
      [key]: prev[key].includes(value) ? prev[key].filter((v) => v !== value) : [...prev[key], value],
    }));
  };

  const handleHtmlFileChange = async (file?: File) => {
    if (!file) return;
    setIsLoadingHtmlFile(true);
    try {
      const text = await file.text();
      setEmailForm((prev) => ({ ...prev, htmlContent: text }));
      toast({ title: t("common.success"), description: "HTML 文件已载入" });
    } catch (error: any) {
      toast({ title: t("common.error"), description: error.message, variant: "destructive" });
    } finally {
      setIsLoadingHtmlFile(false);
      if (htmlFileRef.current) htmlFileRef.current.value = "";
    }
  };

  const handleRecipientsFileChange = async (file?: File) => {
    if (!file) return;
    setIsLoadingRecipientsFile(true);
    try {
      const text = await file.text();
      setEmailForm((prev) => ({ ...prev, fileRecipientsText: text }));
      toast({ title: t("common.success"), description: "收件人文件已载入" });
    } catch (error: any) {
      toast({ title: t("common.error"), description: error.message, variant: "destructive" });
    } finally {
      setIsLoadingRecipientsFile(false);
      if (recipientsFileRef.current) recipientsFileRef.current.value = "";
    }
  };

  const sendEmailMutation = useMutation({
    mutationFn: async () => {
      if (!emailForm.subject.trim()) throw new Error("请输入邮件主题");
      if (!isValidEmail(emailForm.senderEmail)) throw new Error("请输入有效的发件邮箱");
      if (!emailForm.htmlContent.trim()) throw new Error("请输入或上传 HTML 内容");

      const hasManual = manualRecipients.length > 0;
      const hasFile = fileRecipients.length > 0;
      const hasUsers = emailForm.targetType !== "none" && (emailForm.targetType !== "specific" || emailForm.targetUserIds.length > 0);
      const hasRestaurants = emailForm.restaurantEnabled;

      if (!hasManual && !hasFile && !hasUsers && !hasRestaurants) {
        throw new Error("请至少提供一种收件人来源（手动 / 文件 / 站内用户 / 站内餐厅）");
      }

      // Confirmation
      const sources: string[] = [];
      if (hasManual) sources.push(`手动 ${manualRecipients.length}`);
      if (hasFile) sources.push(`文件 ${fileRecipients.length}`);
      if (hasUsers) sources.push(`站内用户`);
      if (hasRestaurants) sources.push(`站内餐厅 约${restaurantPreview.count}`);
      const confirmed = window.confirm(
        `即将发送 HTML 邮件：\n\n主题：${emailForm.subject}\n发件人：${emailForm.senderEmail}\n收件来源：${sources.join(" + ")}\n单批 BCC：${emailForm.batchSize}\n\n确认发送？`,
      );
      if (!confirmed) throw new Error("已取消");

      const { data, error } = await supabase.functions.invoke("send-ad-bulk-email", {
        body: {
          subject: emailForm.subject.trim(),
          previewText: emailForm.previewText.trim() || undefined,
          senderEmail: normalizeEmail(emailForm.senderEmail),
          htmlContent: emailForm.htmlContent,
          manualRecipients,
          fileRecipients,
          targetType: emailForm.targetType,
          targetRole: emailForm.targetType === "role" ? emailForm.targetRole : null,
          targetUserIds: emailForm.targetType === "specific" ? emailForm.targetUserIds : [],
          restaurantFilters: hasRestaurants
            ? {
                enabled: true,
                templates: emailForm.restaurantTemplates,
                cities: emailForm.restaurantCities,
                storeLevels: emailForm.restaurantStoreLevels,
                michelinStars: emailForm.restaurantMichelinStars,
              }
            : { enabled: false },
          batchSize: emailForm.batchSize,
        },
      });

      if (error) throw error;
      return data as { success_count: number; failed_count: number; recipient_count: number };
    },
    onSuccess: (data) => {
      queryClient.invalidateQueries({ queryKey: ["ad-email-send-records"] });
      toast({ title: t("common.success"), description: `已发送 ${data.success_count}/${data.recipient_count}，失败 ${data.failed_count}` });
    },
    onError: (error: any) => {
      if (error.message !== "已取消") {
        toast({ title: t("common.error"), description: error.message, variant: "destructive" });
      }
    },
  });

  const deleteRecordMutation = useMutation({
    mutationFn: async (record: EmailSendRecord) => {
      const { error } = await supabase.from("email_send_records").delete().eq("id", record.id);
      if (error) throw error;
      return record;
    },
    onSuccess: (record) => {
      queryClient.invalidateQueries({ queryKey: ["ad-email-send-records"] });
      toast({ title: t("common.success"), description: `已删除记录：${record.subject}` });
    },
    onError: (error: any) => {
      toast({ title: t("common.error"), description: error.message, variant: "destructive" });
    },
  });

  const handleDeleteRecord = (record: EmailSendRecord) => {
    const confirmed = window.confirm(`确认删除这条群发记录？\n\n${record.subject}`);
    if (!confirmed) return;
    deleteRecordMutation.mutate(record);
  };

  return (
    <div className="space-y-6">
      <div>
        <h1 className="flex items-center gap-2 text-2xl font-bold">
          <Mail className="h-6 w-6" />
          HTML 邮件群发
        </h1>
        <p className="mt-1 text-sm text-muted-foreground">使用 Microsoft 账号进行 HTML 密送群发，支持站内用户、站内餐厅、手动邮箱与文件导入的混合发送。</p>
      </div>

      <Card>
        <CardHeader>
          <CardTitle>发送设置</CardTitle>
        </CardHeader>
        <CardContent className="space-y-6">
          {/* Subject + sender */}
          <div className="grid gap-4 md:grid-cols-2">
            <div>
              <Label>邮件主题</Label>
              <Input value={emailForm.subject} onChange={(e) => setEmailForm((prev) => ({ ...prev, subject: e.target.value }))} />
            </div>
            <div>
              <Label>发件邮箱</Label>
              <Input value={emailForm.senderEmail} onChange={(e) => setEmailForm((prev) => ({ ...prev, senderEmail: e.target.value }))} placeholder="comercial@xiaoxiong.pt" />
            </div>
          </div>

          <div>
            <Label>预览文本</Label>
            <Input value={emailForm.previewText} onChange={(e) => setEmailForm((prev) => ({ ...prev, previewText: e.target.value }))} placeholder="收件人在收件箱中看到的预览文字..." />
          </div>

          {/* HTML content */}
          <div className="space-y-3">
            <div className="flex items-center justify-between">
              <Label>HTML 内容</Label>
              <Button type="button" variant="outline" size="sm" onClick={() => htmlFileRef.current?.click()}>
                {isLoadingHtmlFile ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <Upload className="mr-2 h-4 w-4" />}
                上传 .html
              </Button>
              <input ref={htmlFileRef} type="file" accept=".html,text/html" className="hidden" onChange={(e) => handleHtmlFileChange(e.target.files?.[0])} />
            </div>
            <Textarea className="min-h-[220px] font-mono text-xs" value={emailForm.htmlContent} onChange={(e) => setEmailForm((prev) => ({ ...prev, htmlContent: e.target.value }))} placeholder="<html>...</html>" />
          </div>

          {/* Manual + file recipients */}
          <div className="grid gap-4 md:grid-cols-2">
            <div className="space-y-3">
              <Label>手动邮箱列表</Label>
              <Textarea className="min-h-[140px]" value={emailForm.manualRecipientsText} onChange={(e) => setEmailForm((prev) => ({ ...prev, manualRecipientsText: e.target.value }))} placeholder="a@example.com&#10;b@example.com" />
              <p className="text-xs text-muted-foreground">支持换行、逗号、分号分隔。已识别 <span className="font-semibold">{manualRecipients.length}</span> 个有效邮箱。</p>
            </div>
            <div className="space-y-3">
              <div className="flex items-center justify-between">
                <Label>文件导入邮箱</Label>
                <Button type="button" variant="outline" size="sm" onClick={() => recipientsFileRef.current?.click()}>
                  {isLoadingRecipientsFile ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <Upload className="mr-2 h-4 w-4" />}
                  上传 txt/csv
                </Button>
                <input ref={recipientsFileRef} type="file" accept=".txt,.csv,text/plain,text/csv" className="hidden" onChange={(e) => handleRecipientsFileChange(e.target.files?.[0])} />
              </div>
              <Textarea className="min-h-[140px]" value={emailForm.fileRecipientsText} onChange={(e) => setEmailForm((prev) => ({ ...prev, fileRecipientsText: e.target.value }))} />
              <p className="text-xs text-muted-foreground">已识别 <span className="font-semibold">{fileRecipients.length}</span> 个有效邮箱。</p>
            </div>
          </div>

          {/* Internal users (collapsible) */}
          <div className="rounded-lg border border-border">
            <button type="button" onClick={() => setShowUserSection((v) => !v)} className="flex w-full items-center justify-between px-4 py-3 text-left hover:bg-muted/50">
              <div className="flex items-center gap-2">
                {showUserSection ? <ChevronDown className="h-4 w-4" /> : <ChevronRight className="h-4 w-4" />}
                <Users className="h-4 w-4" />
                <span className="font-medium">站内用户</span>
                {internalUserCount !== null && internalUserCount > 0 && <Badge variant="secondary">{internalUserCount}</Badge>}
                {internalUserCount === null && <Badge variant="secondary">按身份</Badge>}
              </div>
            </button>
            {showUserSection && (
              <div className="space-y-3 border-t border-border p-4">
                <div className="grid gap-4 md:grid-cols-[180px_1fr]">
                  <Select value={emailForm.targetType} onValueChange={(value: "none" | "all" | "role" | "specific") => setEmailForm((prev) => ({ ...prev, targetType: value }))}>
                    <SelectTrigger><SelectValue /></SelectTrigger>
                    <SelectContent>
                      <SelectItem value="none">不发给站内用户</SelectItem>
                      <SelectItem value="all">全部用户</SelectItem>
                      <SelectItem value="role">按身份</SelectItem>
                      <SelectItem value="specific">指定用户</SelectItem>
                    </SelectContent>
                  </Select>

                  {emailForm.targetType === "role" ? (
                    <Select value={emailForm.targetRole} onValueChange={(value) => setEmailForm((prev) => ({ ...prev, targetRole: value }))}>
                      <SelectTrigger><SelectValue /></SelectTrigger>
                      <SelectContent>
                        <SelectItem value="user">普通用户</SelectItem>
                        <SelectItem value="merchant">商家</SelectItem>
                        <SelectItem value="supervisor">主管</SelectItem>
                        <SelectItem value="admin">管理员</SelectItem>
                      </SelectContent>
                    </Select>
                  ) : emailForm.targetType === "specific" ? (
                    <div className="space-y-3">
                      <Input value={emailForm.userSearch} onChange={(e) => setEmailForm((prev) => ({ ...prev, userSearch: e.target.value }))} placeholder="搜索用户..." />
                      <div className="max-h-52 space-y-1 overflow-y-auto rounded-md border border-border p-2">
                        {filteredInternalUsers.slice(0, 100).map((user) => {
                          const checked = emailForm.targetUserIds.includes(user.id);
                          return (
                            <label key={user.id} className="flex cursor-pointer items-center justify-between rounded-md px-2 py-1.5 hover:bg-muted">
                              <div className="min-w-0 flex-1">
                                <div className="truncate text-sm font-medium">{user.display_name || user.email}</div>
                                <div className="truncate text-xs text-muted-foreground">{user.email}</div>
                              </div>
                              <input
                                type="checkbox"
                                checked={checked}
                                onChange={(e) => {
                                  setEmailForm((prev) => ({
                                    ...prev,
                                    targetUserIds: e.target.checked
                                      ? [...prev.targetUserIds, user.id]
                                      : prev.targetUserIds.filter((id) => id !== user.id),
                                  }));
                                }}
                              />
                            </label>
                          );
                        })}
                      </div>
                    </div>
                  ) : emailForm.targetType === "all" ? (
                    <div className="flex items-center rounded-md border border-dashed border-border px-3 text-sm text-muted-foreground">将包含全部 {internalUsers.length} 位站内用户</div>
                  ) : (
                    <div className="flex items-center rounded-md border border-dashed border-border px-3 text-sm text-muted-foreground">已禁用站内用户发送</div>
                  )}
                </div>
              </div>
            )}
          </div>

          {/* Restaurant filters (collapsible) */}
          <div className="rounded-lg border border-border">
            <div className="flex w-full items-center justify-between px-4 py-3">
              <button type="button" onClick={() => setShowRestaurantSection((v) => !v)} className="flex items-center gap-2 text-left">
                {showRestaurantSection ? <ChevronDown className="h-4 w-4" /> : <ChevronRight className="h-4 w-4" />}
                <Building2 className="h-4 w-4" />
                <span className="font-medium">站内餐厅邮箱</span>
                {emailForm.restaurantEnabled && <Badge variant="secondary">{restaurantPreview.count} 家</Badge>}
              </button>
              <div className="flex items-center gap-2">
                <span className="text-xs text-muted-foreground">{emailForm.restaurantEnabled ? "已启用" : "已禁用"}</span>
                <Switch checked={emailForm.restaurantEnabled} onCheckedChange={(checked) => setEmailForm((prev) => ({ ...prev, restaurantEnabled: checked }))} />
              </div>
            </div>

            {showRestaurantSection && emailForm.restaurantEnabled && (
              <div className="space-y-4 border-t border-border p-4">
                {/* Templates */}
                <div>
                  <Label className="mb-2 block">餐厅模板（不选则全部）</Label>
                  <div className="flex flex-wrap gap-2">
                    {RESTAURANT_TEMPLATES.map((tpl) => {
                      const active = emailForm.restaurantTemplates.includes(tpl.value);
                      return (
                        <Button key={tpl.value} type="button" size="sm" variant={active ? "default" : "outline"} onClick={() => toggleArrayValue("restaurantTemplates", tpl.value)}>
                          {tpl.label}
                        </Button>
                      );
                    })}
                  </div>
                </div>

                {/* Store level */}
                <div>
                  <Label className="mb-2 block">认证状态</Label>
                  <div className="flex flex-wrap gap-2">
                    {STORE_LEVELS.map((lvl) => {
                      const active = emailForm.restaurantStoreLevels.includes(lvl.value);
                      return (
                        <Button key={lvl.value} type="button" size="sm" variant={active ? "default" : "outline"} onClick={() => toggleArrayValue("restaurantStoreLevels", lvl.value)}>
                          {lvl.label}
                        </Button>
                      );
                    })}
                  </div>
                </div>

                {/* Michelin stars */}
                {(emailForm.restaurantTemplates.length === 0 || emailForm.restaurantTemplates.includes("michelin")) && (
                  <div>
                    <Label className="mb-2 block">米其林星级</Label>
                    <div className="flex flex-wrap gap-2">
                      {MICHELIN_STARS.map((star) => {
                        const active = emailForm.restaurantMichelinStars.includes(star.value);
                        return (
                          <Button key={star.value} type="button" size="sm" variant={active ? "default" : "outline"} onClick={() => toggleArrayValue("restaurantMichelinStars", star.value)}>
                            {star.label}
                          </Button>
                        );
                      })}
                    </div>
                  </div>
                )}

                {/* Cities */}
                {restaurantCities.length > 0 && (
                  <div>
                    <Label className="mb-2 block">城市（不选则全部，{restaurantCities.length} 个候选）</Label>
                    <div className="max-h-32 overflow-y-auto rounded-md border border-border p-2">
                      <div className="flex flex-wrap gap-1.5">
                        {restaurantCities.map((city) => {
                          const active = emailForm.restaurantCities.includes(city);
                          return (
                            <Button key={city} type="button" size="sm" variant={active ? "default" : "outline"} className="h-7 px-2 text-xs" onClick={() => toggleArrayValue("restaurantCities", city)}>
                              {city}
                            </Button>
                          );
                        })}
                      </div>
                    </div>
                  </div>
                )}

                <div className="rounded-md bg-muted px-3 py-2 text-sm">
                  当前筛选预估收件餐厅数：<span className="font-bold text-foreground">{restaurantPreview.count}</span>
                </div>
              </div>
            )}
          </div>

          {/* Preview + batch */}
          <div className="grid gap-4 md:grid-cols-[1fr_220px]">
            <Card>
              <CardHeader>
                <CardTitle className="text-base">发送预览</CardTitle>
              </CardHeader>
              <CardContent className="grid gap-3 sm:grid-cols-2 lg:grid-cols-5">
                <div className="rounded-md border border-border p-3"><div className="text-xs text-muted-foreground">手动</div><div className="text-xl font-semibold">{manualRecipients.length}</div></div>
                <div className="rounded-md border border-border p-3"><div className="text-xs text-muted-foreground">文件</div><div className="text-xl font-semibold">{fileRecipients.length}</div></div>
                <div className="rounded-md border border-border p-3"><div className="text-xs text-muted-foreground">站内用户</div><div className="text-xl font-semibold">{internalUserCount === null ? "按身份" : internalUserCount}</div></div>
                <div className="rounded-md border border-border p-3"><div className="text-xs text-muted-foreground">站内餐厅</div><div className="text-xl font-semibold">{emailForm.restaurantEnabled ? restaurantPreview.count : 0}</div></div>
                <div className="rounded-md border border-primary p-3"><div className="text-xs text-muted-foreground">合计预估</div><div className="text-xl font-semibold text-primary">≈ {totalPreviewRecipients}</div></div>
              </CardContent>
            </Card>
            <div className="space-y-2 rounded-lg border border-border p-4">
              <Label>单批 BCC 数</Label>
              <Input type="number" min={1} max={MAX_BATCH_SIZE} value={emailForm.batchSize} onChange={(e) => setEmailForm((prev) => ({ ...prev, batchSize: Math.max(1, Math.min(MAX_BATCH_SIZE, parseInt(e.target.value) || MAX_BATCH_SIZE)) }))} />
              <p className="text-xs text-muted-foreground">每批 BCC 人数（1-100）。最终邮箱发送服务上限决定。</p>
            </div>
          </div>

          <div className="flex justify-end">
            <Button onClick={() => sendEmailMutation.mutate()} disabled={sendEmailMutation.isPending} size="lg">
              {sendEmailMutation.isPending ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <Send className="mr-2 h-4 w-4" />}
              发送
            </Button>
          </div>
        </CardContent>
      </Card>

      {/* Send records */}
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2 text-base"><Users className="h-4 w-4" />最近群发记录</CardTitle>
        </CardHeader>
        <CardContent className="p-0">
          {sendRecordsLoading ? (
            <div className="space-y-3 p-6">{[1, 2].map((i) => <Skeleton key={i} className="h-12 w-full" />)}</div>
          ) : sendRecords.length === 0 ? (
            <div className="p-6 text-sm text-muted-foreground">暂无群发记录</div>
          ) : (
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead>邮件主题</TableHead>
                  <TableHead>发件人</TableHead>
                  <TableHead>人数</TableHead>
                  <TableHead>成功</TableHead>
                  <TableHead>失败</TableHead>
                  <TableHead>发送时间</TableHead>
                  <TableHead className="w-32 text-right">操作</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {sendRecords.map((record) => {
                  const isDeleting = deleteRecordMutation.isPending && deleteRecordMutation.variables?.id === record.id;
                  return (
                    <TableRow key={record.id}>
                      <TableCell className="max-w-[280px] truncate font-medium">{record.subject}</TableCell>
                      <TableCell className="text-sm text-muted-foreground">{record.sender_email || "—"}</TableCell>
                      <TableCell>{record.recipient_count ?? record.sent_count}</TableCell>
                      <TableCell>{record.success_count}</TableCell>
                      <TableCell>{record.failed_count}</TableCell>
                      <TableCell>{format(new Date(record.sent_at), "yyyy-MM-dd HH:mm")}</TableCell>
                      <TableCell className="text-right">
                        <Button type="button" variant="outline" size="sm" onClick={() => handleDeleteRecord(record)} disabled={isDeleting}>
                          {isDeleting ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <Trash2 className="mr-2 h-4 w-4" />}
                          删除
                        </Button>
                      </TableCell>
                    </TableRow>
                  );
                })}
              </TableBody>
            </Table>
          )}
        </CardContent>
      </Card>
    </div>
  );
}
